struct half2 {
  float x;
  float y;
};

static inline half2 operator+(const half2& a, const half2& b) {
  return {a.x + b.x, a.y + b.y};
}
static inline half2 operator*(const half2& a, const half2& b) {
  return {a.x * b.x, a.y * b.y};
}
static inline bool operator==(const half2& a, const half2& b) {
  return a.x == b.x && a.y == b.y;
}

template <typename T>
static inline T zero_value();
template <>
inline int zero_value<int>() {
  return 0;
}
template <>
inline float zero_value<float>() {
  return 0.0f;
}
template <>
inline double zero_value<double>() {
  return 0.0;
}
template <>
inline half2 zero_value<half2>() {
  return {0.0f, 0.0f};
}

template <typename T>
static inline T neg_one_value();
template <>
inline int neg_one_value<int>() {
  return -1;
}
template <>
inline float neg_one_value<float>() {
  return -1.0f;
}
template <>
inline double neg_one_value<double>() {
  return -1.0;
}
template <>
inline half2 neg_one_value<half2>() {
  return {-1.0f, -1.0f};
}

template <int N, class F>
double benchmark(F&& fn) {
  double best = std::numeric_limits<double>::max();
  for (int i = 0; i < N; i++) {
    double t = fn();
    if (t < best) best = t;
  }
  return best;
}

double now_ms() {
  auto t = std::chrono::high_resolution_clock::now().time_since_epoch();
  return std::chrono::duration<double, std::milli>(t).count();
}

void flushed_printf(const char* format, ...) {
  va_list args;
  va_start(args, format);
  vprintf(format, args);
  va_end(args);
  fflush(stdout);
}

void show_progress_init(int length) {
  flushed_printf("[");
  for (int i = 0; i < length; i++) flushed_printf(" ");
  flushed_printf("]");
  for (int i = 0; i <= length; i++) flushed_printf("\b");
}

void show_progress_step(int domove, char newchar) {
  flushed_printf("%c", newchar);
  if (!domove) flushed_printf("\b");
}

void show_progress_done(void) { flushed_printf("\n"); }

