inline size_t GetMaxDeviceWGSize(cl_device_id) { return (size_t)1 << 20; }

bool argument_parsing(int argc, char* argv[], ArgParams* output) {
  int arg_count = 0;
  for (int i = 1; i < argc; i++) {
    if ((strcmp(argv[i], "-h") == 0) || (strcmp(argv[i], "--help") == 0)) {
      return false;
    } else if ((strcmp(argv[i], "-w") == 0) ||
               (strcmp(argv[i], "--workgroup-stride") == 0)) {
      output->block_strided = true;
    } else if ((strcmp(argv[i], "-H") == 0) ||
               (strcmp(argv[i], "--host-alloc") == 0)) {
      output->host_allocated = true;
    } else if ((strcmp(argv[i], "-t") == 0) ||
               (strcmp(argv[i], "--use-os-timer") == 0)) {
      output->use_os_timer = true;
    } else {
      unsigned long value = strtoul(argv[i], NULL, 10);
      switch (arg_count) {
        case 0:
          output->device_index = (int)value;
          arg_count++;
          break;
        case 1:
          output->wg_size = (int)value;
          arg_count++;
          break;
        case 2:
          output->vecwidth = (unsigned int)value;
          arg_count++;
          break;
        case 3:
          output->elements_per_wi = (unsigned int)value;
          arg_count++;
          break;
        case 4:
          output->fusion_degree = (unsigned int)value;
          arg_count++;
          break;
        default:
          return false;
      }
    }
  }
  return true;
}

template <typename T>
void run_kernel(T seed, T* g_data, long size, bool block_strided, size_t workgroupsize,
                unsigned int elements_per_wi, unsigned int fusion_degree,
                int compute_iters) {
  const long compute_grid_size = size / (long)elements_per_wi / (long)fusion_degree;
  if (compute_grid_size <= 0) return;
  const long num_groups = (long)(compute_grid_size / (long)workgroupsize);
  const long big_stride = num_groups * (long)workgroupsize * (long)elements_per_wi;

#pragma omp parallel
  {
    std::vector<T> tmps(elements_per_wi);

#pragma omp for schedule(static)
    for (long gid = 0; gid < compute_grid_size; gid++) {
      long idx, stride;
      if (block_strided) {
        const long group_id = gid / (long)workgroupsize;
        const long local_id = gid % (long)workgroupsize;
        stride = (long)workgroupsize;
        idx = group_id * (long)workgroupsize * (long)elements_per_wi + local_id;
      } else {
        const long grid_size = (long)workgroupsize * num_groups;
        stride = grid_size;
        idx = gid;
      }

      for (unsigned int k = 0; k < fusion_degree; k++) {
        for (unsigned int j = 0; j < elements_per_wi; j++) {
          long at = idx + (long)j * stride + (long)k * big_stride;
          tmps[j] = g_data[at];
          for (int i = 0; i < compute_iters; i++) {
            tmps[j] = tmps[j] * tmps[j] + seed;
          }
        }

        T sum = zero_value<T>();
        for (unsigned int j = 0; j + 1 < elements_per_wi; j += 2) {
          sum = sum + tmps[j] * tmps[j + 1];
        }

        if (sum == neg_one_value<T>()) {
          g_data[idx + (long)k * big_stride] = sum;
        }
      }
    }
  }
}

void runbench_warmup(void* buffer, long size, size_t workgroupsize) {
  (void)workgroupsize;
  const long reduced_grid_size = size / 256;
  short* g_data = reinterpret_cast<short*>(buffer);
  const short seed = 1;

#pragma omp parallel for schedule(static)
  for (long gid = 0; gid < reduced_grid_size; gid++) {
    long idx = gid;
    short v = g_data[idx];
    g_data[idx] = (short)(v * v + seed);
  }
}

void runbench(const int compute_iterations[],
              unsigned int krn_idx,
              void* buffer,
              long size,
              bool block_strided,
              size_t workgroupsize,
              unsigned int elements_per_wi,
              unsigned int fusion_degree,
              bool use_os_timer,
              bool enable_dp,
              bool enable_hp) {
  (void)use_os_timer;
  const long compute_grid_size = size / elements_per_wi / fusion_degree;
  const int current_compute_iterations = compute_iterations[krn_idx];
  const long long computations =
      (elements_per_wi * (long long)compute_grid_size +
       (2 * elements_per_wi * current_compute_iterations) *
           (long long)compute_grid_size) *
      fusion_degree;
  const long long memoryoperations = size;
  constexpr auto total_bench_iterations = 3;

  double kernel_time_mad_sp = benchmark<total_bench_iterations>([&]() {
    const float seed_f = 1.0f;
    double ts = now_ms();
    run_kernel<float>(seed_f, reinterpret_cast<float*>(buffer), size, block_strided,
                      workgroupsize, elements_per_wi, fusion_degree,
                      current_compute_iterations);
    return now_ms() - ts;
  });

  double kernel_time_mad_dp = benchmark<total_bench_iterations>([&]() {
    if (!enable_dp) return 0.0;
    const double seed_d = 1.0;
    double ts = now_ms();
    run_kernel<double>(seed_d, reinterpret_cast<double*>(buffer), size, block_strided,
                       workgroupsize, elements_per_wi, fusion_degree,
                       current_compute_iterations);
    return now_ms() - ts;
  });

  double kernel_time_mad_hp = benchmark<total_bench_iterations>([&]() {
    if (!enable_hp) return 0.0;
    const half2 seed_h = {1.0f, 1.0f};
    double ts = now_ms();
    run_kernel<half2>(seed_h, reinterpret_cast<half2*>(buffer), size, block_strided,
                      workgroupsize, elements_per_wi, fusion_degree,
                      current_compute_iterations);
    return now_ms() - ts;
  });

  double kernel_time_mad_int = benchmark<total_bench_iterations>([&]() {
    const int seed_i = 1;
    double ts = now_ms();
    run_kernel<int>(seed_i, reinterpret_cast<int*>(buffer), size, block_strided,
                    workgroupsize, elements_per_wi, fusion_degree,
                    current_compute_iterations);
    return now_ms() - ts;
  });

  printf(
      "         %4d,   %8.3f,%8.2f,%8.2f,%7.2f,   %8.3f,%8.2f,%8.2f,%7.2f,   "
      "%8.3f,%8.2f,%8.2f,%7.2f,  %8.3f,%8.2f,%8.2f,%7.2f\n",
      current_compute_iterations,
      ((double)computations) / ((double)memoryoperations * sizeof(float)),
      kernel_time_mad_sp,
      ((double)computations) / kernel_time_mad_sp * 1000. /
          (double)(1000 * 1000 * 1000),
      ((double)memoryoperations * sizeof(float)) / kernel_time_mad_sp * 1000. /
          (1000. * 1000. * 1000.),
      ((double)computations) / ((double)memoryoperations * sizeof(double)),
      kernel_time_mad_dp,
      ((double)computations) / kernel_time_mad_dp * 1000. /
          (double)(1000 * 1000 * 1000),
      ((double)memoryoperations * sizeof(double)) / kernel_time_mad_dp * 1000. /
          (1000. * 1000. * 1000.),
      ((double)2 * computations) / ((double)memoryoperations * sizeof(half2)),
      kernel_time_mad_hp,
      ((double)2 * computations) / kernel_time_mad_hp * 1000. /
          (double)(1000 * 1000 * 1000),
      ((double)memoryoperations * sizeof(half2)) / kernel_time_mad_hp * 1000. /
          (1000. * 1000. * 1000.),
      ((double)computations) / ((double)memoryoperations * sizeof(int)),
      kernel_time_mad_int,
      ((double)computations) / kernel_time_mad_int * 1000. /
          (double)(1000 * 1000 * 1000),
      ((double)memoryoperations * sizeof(int)) / kernel_time_mad_int * 1000. /
          (1000. * 1000. * 1000.));
}

extern "C" void mixbenchGPU(cl_device_id dev_id,
                            double* c,
                            long size,
                            bool block_strided,
                            bool host_allocated,
                            bool use_os_timer,
                            size_t workgroupsize,
                            unsigned int elements_per_wi,
                            unsigned int fusion_degree) {
  (void)dev_id;
  const char* benchtype = block_strided ? "Workgroup" : "NDRange";
  printf("Workitem stride:        %s\n", benchtype);
  const char* buffer_allocation =
      host_allocated ? "Host allocated" : "Device allocated";
  printf("Buffer allocation:      %s\n", buffer_allocation);
  printf("Timer:                  %s\n", use_os_timer ? "OS based" : "CL event based");

  bool enable_dp = true;
  bool enable_hp = false;
  if (!enable_dp)
    printf("Warning:                Double precision computations are not supported\n");
  if (!enable_hp)
    printf("Warning:                Half precision computations are not supported\n");

  void* c_buffer = std::malloc((size_t)size * sizeof(double));
  if (!c_buffer) {
    fprintf(stderr, "Error: cannot allocate buffer\n");
    std::exit(1);
  }

  int* mapped_data = reinterpret_cast<int*>(c_buffer);
  for (int i = 0; i < size; i++) mapped_data[i] = 0;

  printf("Loading kernel source file...\n");
  printf("Precompilation of kernels... ");
  show_progress_init(compute_iterations_len);
  for (int i = 0; i < compute_iterations_len; i++) {
    show_progress_step(0, '\\');
    show_progress_step(0, '|');
    if (enable_dp) show_progress_step(0, '/');
    if (enable_hp) show_progress_step(0, '-');
    show_progress_step(1, '>');
  }
  show_progress_done();

  runbench_warmup(c_buffer, size, workgroupsize);

  printf(
      "----------------------------------------------------------------------------- CSV data "
      "-----------------------------------------------------------------------------"
      "-----\n");
  printf(
      "Experiment ID, Single Precision ops,,,,              Double precision "
      "ops,,,,              Half precision ops,,,,                Integer "
      "operations,,, \n");
  printf(
      "Compute iters, Flops/byte, ex.time,  GFLOPS, GB/sec, Flops/byte, "
      "ex.time,  GFLOPS, GB/sec, Flops/byte, ex.time,  GFLOPS, GB/sec, "
      "Iops/byte, ex.time,   GIOPS, GB/sec\n");

  for (int i = 0; i < compute_iterations_len; i++) {
    runbench(compute_iterations, i, c_buffer, size, block_strided, workgroupsize,
             elements_per_wi, fusion_degree, use_os_timer, enable_dp, enable_hp);
  }

  printf(
      "------------------------------------------------------------------------"
      "------------------------------------------------------------------------"
      "--------------------\n");

  std::memcpy(c, c_buffer, (size_t)size * sizeof(double));
  std::free(c_buffer);
}

int main(int argc, char* argv[]) {
  printf("mixbench-ocl (%s)\n", VERSION_INFO);

  ArgParams args = {1, false, false, false, 256,
                    DEF_VECTOR_SIZE / (1024 * 1024), 8, 4};

  if (!argument_parsing(argc, argv, &args)) {
    printf("Usage: mixbench-ocl [options] [device index [workgroup size [array size(1024^2) [elements per workitem [fusion degree]]]]]\n");
    printf(
        "\nOptions:\n"
        "  -h or --help              Show this message\n"
        "  -H or --host-alloc        Use host allocated buffer (CL_MEM_ALLOC_HOST_PTR)\n"
        "  -w or --workgroup-stride  Workitem strides equal to the width of a workgroup length (default: NDRange length)\n"
        "  -t or --use-os-timer      Use standard OS timer instead of OpenCL profiling timer\n"
        "\n");

    GetDeviceID(0, stdout);
    exit(1);
  }

  printf("Use \"-h\" argument to see available options\n");

  const size_t VEC_WIDTH = 1024 * 1024 * args.vecwidth;
  unsigned int datasize = (unsigned int)(VEC_WIDTH * sizeof(double));

  cl_device_id dev_id = GetDeviceID(args.device_index, NULL);

  if (dev_id == 0) {
    fprintf(stderr, "Error: No OpenCL device selected\n");
    exit(1);
  }
  StoreDeviceInfo(dev_id, stdout);

  printf("Buffer size:            %dMB\n", datasize / (1024 * 1024));
  printf("Workgroup size:         %d\n", args.wg_size);
  printf("Elements per workitem:  %d\n", args.elements_per_wi);
  printf("Workitem fusion degree: %d\n", args.fusion_degree);

  if (GetMaxDeviceWGSize(dev_id) < (size_t)args.wg_size) {
    fprintf(stderr, "Error: Unsupported workgroup size (%u).\n", args.wg_size);
    exit(1);
  }

  double* c = (double*)malloc(datasize);
  if (!c) {
    fprintf(stderr, "Error: memory allocation failed\n");
    exit(1);
  }

  mixbenchGPU(dev_id, c, (long)VEC_WIDTH, args.block_strided, args.host_allocated,
              args.use_os_timer, (size_t)args.wg_size, args.elements_per_wi,
              args.fusion_degree);

  free(c);
  return 0;
}
